from dataclasses import dataclass, field
from datetime import date
from typing import Literal

FilterStatus = Literal["ALL_ON", "PARTIAL", "OFF"]

@dataclass
class DeploymentRecord:
    deployment_id: str
    model_name: str
    model_version: str
    use_case: str
    is_commercial: bool
    filter_status: FilterStatus
    filter_config: dict              # exact configuration snapshot
    licence_scope_verified: bool     # confirmed use is within enterprise licence
    deployment_date: date
    last_reviewed: date
    review_owner: str

    def indemnification_eligible(self) -> bool:
        """
        True only when all conditions for indemnification coverage are met.
        A deployment with filters off or unverified licence scope is uncovered.
        """
        return (
            self.filter_status == "ALL_ON" and
            self.licence_scope_verified and
            self.is_model_supported()
        )

    def is_model_supported(self) -> bool:
        # In practice, check against vendor's current supported model list
        # Simplified here: version must not be marked 'deprecated'
        return "deprecated" not in self.model_version.lower()

    def eligibility_status(self) -> str:
        if self.indemnification_eligible():
            return "COVERED"
        reasons = []
        if self.filter_status != "ALL_ON":
            reasons.append(f"safety filters {self.filter_status}")
        if not self.licence_scope_verified:
            reasons.append("licence scope not verified")
        if not self.is_model_supported():
            reasons.append("deprecated model version")
        return f"NOT COVERED ({'; '.join(reasons)})"


@dataclass
class DeploymentRegistry:
    deployments: list[DeploymentRecord] = field(default_factory=list)

    def uncovered_commercial(self) -> list[DeploymentRecord]:
        return [d for d in self.deployments
                if d.is_commercial and not d.indemnification_eligible()]

    def registry_summary(self) -> str:
        total = len(self.deployments)
        commercial = [d for d in self.deployments if d.is_commercial]
        covered = [d for d in commercial if d.indemnification_eligible()]
        return (
            f"Deployments: {total} total | {len(commercial)} commercial | "
            f"{len(covered)}/{len(commercial)} covered | "
            f"{len(self.uncovered_commercial())} NOT COVERED"
        )
